import React, { useEffect, useState } from "react";
import API from "../services/api";
import Navbar from "../components/Navbar";

function FeedingSchedules() {
  const [schedules, setSchedules] = useState([]);
  const [animals, setAnimals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState(null);

  const [formData, setFormData] = useState({
    foodName: "",
    feedingDate: "",
    feedingTime: "",
    keeperName: "",
    animalId: "",
  });

  useEffect(() => {
    fetchSchedules();
    fetchAnimals();
  }, []);

  const fetchSchedules = async () => {
    try {
      const res = await API.get("/feeding-schedules");
      setSchedules(res.data);
    } catch (error) {
      console.error("Error fetching feeding schedules:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchAnimals = async () => {
    try {
      const res = await API.get("/animals");
      setAnimals(res.data);
    } catch (error) {
      console.error("Error fetching animals:", error);
    }
  };

  const resetForm = () => {
    setFormData({
      foodName: "",
      feedingDate: "",
      feedingTime: "",
      keeperName: "",
      animalId: "",
    });
    setEditingId(null);
  };

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      foodName: formData.foodName,
      feedingDate: formData.feedingDate,
      feedingTime: formData.feedingTime,
      keeperName: formData.keeperName,
      animal: formData.animalId ? { id: Number(formData.animalId) } : null,
    };

    try {
      if (editingId) {
        await API.put(`/feeding-schedules/${editingId}`, payload);
        alert("Feeding schedule updated successfully");
      } else {
        await API.post("/feeding-schedules", payload);
        alert("Feeding schedule added successfully");
      }

      resetForm();
      fetchSchedules();
    } catch (error) {
      console.error("Error saving feeding schedule:", error);

      if (error.response?.data) {
        const data = error.response.data;
        if (typeof data === "object") {
          const firstError = Object.values(data)[0];
          alert(firstError);
        } else {
          alert("Failed to save feeding schedule");
        }
      } else {
        alert("Failed to save feeding schedule");
      }
    }
  };

  const handleEdit = (schedule) => {
    setEditingId(schedule.id);
    setFormData({
      foodName: schedule.foodName || "",
      feedingDate: schedule.feedingDate || "",
      feedingTime: schedule.feedingTime || "",
      keeperName: schedule.keeperName || "",
      animalId: schedule.animal?.id || "",
    });

    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm(
      "Are you sure you want to delete this feeding schedule?"
    );
    if (!confirmDelete) return;

    try {
      await API.delete(`/feeding-schedules/${id}`);
      alert("Feeding schedule deleted successfully");
      fetchSchedules();
    } catch (error) {
      console.error("Error deleting feeding schedule:", error);
      alert("Failed to delete feeding schedule");
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <div style={styles.header}>
          <h1 style={styles.title}>Feeding Schedules Management</h1>
          <p style={styles.subtitle}>
            Add, update, view, and manage animal feeding schedules from one place.
          </p>
        </div>

        <div style={styles.formCard}>
          <h2 style={styles.cardTitle}>
            {editingId ? "Update Feeding Schedule" : "Add New Feeding Schedule"}
          </h2>

          <form onSubmit={handleSubmit} style={styles.formGrid}>
            <input
              type="text"
              name="foodName"
              placeholder="Food Name"
              value={formData.foodName}
              onChange={handleChange}
              style={styles.input}
            />

            <input
              type="date"
              name="feedingDate"
              value={formData.feedingDate}
              onChange={handleChange}
              style={styles.input}
            />

            <input
              type="time"
              name="feedingTime"
              value={formData.feedingTime}
              onChange={handleChange}
              style={styles.input}
            />

            <input
              type="text"
              name="keeperName"
              placeholder="Keeper Name"
              value={formData.keeperName}
              onChange={handleChange}
              style={styles.input}
            />

            <select
              name="animalId"
              value={formData.animalId}
              onChange={handleChange}
              style={styles.input}
            >
              <option value="">Select Animal</option>
              {animals.map((animal) => (
                <option key={animal.id} value={animal.id}>
                  {animal.name} - {animal.species}
                </option>
              ))}
            </select>

            <div style={styles.buttonRow}>
              <button type="submit" style={styles.primaryBtn}>
                {editingId ? "Update Schedule" : "Add Schedule"}
              </button>

              {editingId && (
                <button
                  type="button"
                  style={styles.cancelBtn}
                  onClick={resetForm}
                >
                  Cancel
                </button>
              )}
            </div>
          </form>
        </div>

        <div style={styles.listSection}>
          <h2 style={styles.cardTitle}>Feeding Schedules List</h2>

          {loading ? (
            <p>Loading feeding schedules...</p>
          ) : schedules.length === 0 ? (
            <p>No feeding schedules found.</p>
          ) : (
            <div style={styles.grid}>
              {schedules.map((schedule) => (
                <div key={schedule.id} style={styles.scheduleCard}>
                  <h3 style={styles.scheduleTitle}>
                    {schedule.animal?.name || "Animal Not Assigned"}
                  </h3>
                  <p><strong>Species:</strong> {schedule.animal?.species || "-"}</p>
                  <p><strong>Food:</strong> {schedule.foodName}</p>
                  <p><strong>Date:</strong> {schedule.feedingDate}</p>
                  <p><strong>Time:</strong> {schedule.feedingTime}</p>
                  <p><strong>Keeper:</strong> {schedule.keeperName}</p>

                  <div style={styles.actionRow}>
                    <button
                      style={styles.editBtn}
                      onClick={() => handleEdit(schedule)}
                    >
                      Edit
                    </button>

                    <button
                      style={styles.deleteBtn}
                      onClick={() => handleDelete(schedule.id)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #eef2ff, #f8fafc)",
    fontFamily: "Arial, sans-serif",
  },
  container: {
    width: "90%",
    maxWidth: "1200px",
    margin: "0 auto",
    padding: "30px 0 50px",
  },
  header: {
    background: "linear-gradient(135deg, #ffffff, #eff6ff)",
    padding: "30px",
    borderRadius: "20px",
    boxShadow: "0 10px 24px rgba(0,0,0,0.08)",
    marginBottom: "25px",
  },
  title: {
    fontSize: "2.2rem",
    color: "#111827",
    marginBottom: "10px",
  },
  subtitle: {
    color: "#4b5563",
    fontSize: "1rem",
    lineHeight: "1.7",
  },
  formCard: {
    background: "#fff",
    padding: "25px",
    borderRadius: "18px",
    boxShadow: "0 8px 20px rgba(0,0,0,0.08)",
    marginBottom: "30px",
  },
  cardTitle: {
    fontSize: "1.5rem",
    marginBottom: "20px",
    color: "#111827",
  },
  formGrid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))",
    gap: "16px",
  },
  input: {
    padding: "13px 15px",
